const r="/api";function s(n){const t=n.startsWith("/")?n:`/${n}`;return`${r}${t}`}async function a(n){const t=await fetch(s(n));if(!t.ok)throw new Error(`请求失败: ${t.status}`);return t.json()}async function e(n,t){const o=await fetch(s(n),{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)});if(!o.ok)throw new Error(`保存失败: ${o.status}`);return o.json()}async function i(n,t){const o=await fetch(s(n),{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)});if(!o.ok)throw new Error(`更新失败: ${o.status}`);return o.json()}async function c(n){const t=await fetch(s(n),{method:"DELETE"});if(!t.ok&&t.status!==404)throw new Error(`删除失败: ${t.status}`)}export{a,i as b,c,e as d};
